import { Link } from "react-router-dom";
import { questions } from "../data/questions";

function Dashboard() {
  return (
    <div className="page-center">
      <div className="card">

        <div style={{ textAlign: "center", marginBottom: "20px" }}>
          <h2 style={{ color: "#1976d2", marginBottom: "5px" }}>
            Dashboard
          </h2>
          <p style={{ fontSize: "14px", color: "#666" }}>
            Questions from Juniors
          </p>
        </div>

        {questions.map((q) => (
          <div
            key={q.id}
            style={{
              border: "1px solid #ddd",
              padding: "15px",
              borderRadius: "8px",
              marginBottom: "15px",
              backgroundColor: "#fafafa"
            }}
          >
            <h4 style={{ marginBottom: "8px" }}>{q.title}</h4>
            <p style={{ fontSize: "14px", color: "#555" }}>
              {q.description}
            </p>

            <div style={{ display: "flex", justifyContent: "space-between" }}>
              <span style={{ fontSize: "12px", color: "#777" }}>
                Asked by Junior
              </span>

              <Link
                to="/answers"
                style={{
                  fontSize: "13px",
                  padding: "6px 12px",
                  backgroundColor: "#1976d2",
                  color: "white",
                  borderRadius: "4px",
                  textDecoration: "none"
                }}
              >
                View Answer
              </Link>
            </div>
          </div>
        ))}

        <Link className="btn" to="/ask">
          Ask New Question
        </Link>

      </div>
    </div>
  );
}

export default Dashboard;
